// Component (e.g., MessagesComponent)
async onSend(body: string): Promise<void> {
  const tempId = crypto.randomUUID();
  this.messages.update(list => [...list, { id: tempId, body, pending: true, ... }]);
  try {
    await this.dc.sendMessage(body);
    // server-confirmed list refreshes via getMessages() — the pending entry is replaced by the real one
    await this.refreshMessages();
  } catch (err) {
    this.messages.update(list => list.filter(m => m.id !== tempId));
    this.toast.error('Could not send. Try again.');
  }
}
